import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card"
import { Check } from "lucide-react"

const plans = [
    {
        name: "Active Quality",
        price: "$",
        description: "Ideal para empezar",
        features: ["Followers reales", "Likes graduales", "Entrega inmediata", "Soporte básico"],
        buttonText: "Comprar",
        popular: false,
    },
    {
        name: "Premium Quality",
        price: "$$",
        description: "Para creadores serios",
        features: ["Followers alta calidad", "Likes instantáneos", "Garantía de refill", "Soporte prioritario"],
        buttonText: "Comprar",
        popular: true,
    },
    {
        name: "VIP Quality",
        price: "$$$",
        description: "Máximo impacto",
        features: ["Followers nicho", "Engagement real", "Garantía de por vida", "Account Manager"],
        buttonText: "Comprar",
        popular: false,
    },
]

export function PricingCards() {
    return (
        <section id="pricing" className="py-20 bg-white">
            <div className="container px-4 md:px-6 mx-auto">
                <div className="text-center mb-12">
                    <h2 className="text-3xl font-bold tracking-tighter sm:text-4xl md:text-5xl">
                        Packs y Promociones
                    </h2>
                    <p className="mt-4 text-gray-500 md:text-xl">
                        Calidad garantizada para todos los presupuestos.
                    </p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    {plans.map((plan, index) => (
                        <Card key={index} className={`flex flex-col ${plan.popular ? 'border-blue-600 shadow-xl scale-105' : ''}`}>
                            <CardHeader>
                                <CardTitle className="text-2xl">{plan.name}</CardTitle>
                                <CardDescription>{plan.description}</CardDescription>
                            </CardHeader>
                            <CardContent className="flex-1">
                                <div className="text-4xl font-bold mb-6">{plan.price}</div>
                                <ul className="space-y-3">
                                    {plan.features.map((feature, i) => (
                                        <li key={i} className="flex items-center">
                                            <Check className="w-5 h-5 text-green-500 mr-2" />
                                            <span className="text-gray-600">{feature}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                            <CardFooter>
                                <Button className="w-full" variant={plan.popular ? "default" : "outline"}>
                                    {plan.buttonText}
                                </Button>
                            </CardFooter>
                        </Card>
                    ))}
                </div>
            </div>
        </section>
    )
}
